-- Create medicinal plants table
CREATE TABLE public.medicinal_plants (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  common_name TEXT NOT NULL,
  scientific_name TEXT NOT NULL,
  category TEXT NOT NULL,
  parts_used TEXT[] NOT NULL,
  medicinal_properties TEXT[] NOT NULL,
  common_uses TEXT[] NOT NULL,
  precautions TEXT,
  description TEXT NOT NULL,
  image_keywords TEXT[] NOT NULL, -- Keywords for image matching
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.medicinal_plants ENABLE ROW LEVEL SECURITY;

-- Allow public read access (no authentication needed for viewing plants)
CREATE POLICY "Anyone can view medicinal plants"
ON public.medicinal_plants
FOR SELECT
USING (true);

-- Create index for faster searches
CREATE INDEX idx_medicinal_plants_common_name ON public.medicinal_plants(common_name);
CREATE INDEX idx_medicinal_plants_scientific_name ON public.medicinal_plants(scientific_name);

-- Insert 100 medicinal plants with comprehensive data

-- Create function to update timestamps
CREATE OR REPLACE FUNCTION public.update_medicinal_plants_timestamp()
RETURNS TRIGGER
LANGUAGE plpgsql
SET search_path = public
AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;

-- Create trigger for automatic timestamp updates
CREATE TRIGGER update_medicinal_plants_updated_at
BEFORE UPDATE ON public.medicinal_plants
FOR EACH ROW
EXECUTE FUNCTION public.update_medicinal_plants_timestamp();